describe('loadBlockedWords', () => {
    beforeEach(() => {
        jest.clearAllMocks();
    });

    it('loads words from AsyncStorage when DB has not changed', async () => {
        const storedWords = ['badword', 'slur'];
        const lastModified = '2026-01-01T00:00:00Z';

        mockedStorage.getItem
            .mockResolvedValueOnce(lastModified)                        // last_modified
            .mockResolvedValueOnce(JSON.stringify(storedWords));        // list

        mockFrom.mockReturnValue({
            select: jest.fn().mockReturnValue({
                order: jest.fn().mockReturnValue({
                    limit: jest.fn().mockReturnValue({
                        single: jest.fn().mockResolvedValue({
                            data: { created_at: lastModified }, error: null,
                        }),
                    }),
                }),
            }),
        });
        await loadBlockedWords();

        expect(isProfane('badword')).toBe(true);
        expect(isProfane('hello')).toBe(false);
    });

    it('fetches from DB and updates cache when DB has changed', async () => {
        const oldModified = '2026-01-01T00:00:00Z';
        const newModified = '2026-02-01T00:00:00Z';

        mockedStorage.getItem
            .mockResolvedValueOnce(oldModified)                         // last_modified
            .mockResolvedValueOnce(JSON.stringify(['oldword']));        // list (ignored)

        mockFrom
            .mockReturnValueOnce({
                select: jest.fn().mockReturnValue({
                    order: jest.fn().mockReturnValue({
                        limit: jest.fn().mockReturnValue({
                            single: jest.fn().mockResolvedValue({
                                data: { created_at: newModified }, error: null,
                            }),
                        }),
                    }),
                }),
            })
            .mockReturnValueOnce({
                select: jest.fn().mockReturnValue({
                    order: jest.fn().mockResolvedValue({
                        data: [{ word: 'newword' }], error: null,
                    }),
                }),
            });
        await loadBlockedWords();

        expect(isProfane('newword')).toBe(true);
        expect(mockedStorage.setItem).toHaveBeenCalledWith(
            BLOCKED_WORDS_LIST_KEY,
            JSON.stringify(['newword'])
        );
        expect(mockedStorage.setItem).toHaveBeenCalledWith(
            BLOCKED_WORDS_MODIFIED_KEY,
            newModified
        );
    });

    it('fetches from DB when no cache exists', async () => {
        mockedStorage.getItem.mockResolvedValue(null);

        mockFrom
            .mockReturnValueOnce({
                select: jest.fn().mockReturnValue({
                    order: jest.fn().mockReturnValue({
                        limit: jest.fn().mockReturnValue({
                            single: jest.fn().mockResolvedValue({
                                data: { created_at: '2026-01-01T00:00:00Z' }, error: null,
                            }),
                        }),
                    }),
                }),
            })
            .mockReturnValueOnce({
                select: jest.fn().mockReturnValue({
                    order: jest.fn().mockResolvedValue({
                        data: [{ word: 'freshword' }], error: null,
                    }),
                }),
            });
        await loadBlockedWords();

        expect(isProfane('freshword')).toBe(true);
    });

    it('falls back to cached words when DB check fails', async () => {
        mockedStorage.getItem
            .mockResolvedValueOnce('2026-01-01T00:00:00Z')
            .mockResolvedValueOnce(JSON.stringify(['fallbackword']));

        mockFrom.mockReturnValue({
            select: jest.fn().mockReturnValue({
                order: jest.fn().mockReturnValue({
                    limit: jest.fn().mockReturnValue({
                        single: jest.fn().mockResolvedValue({
                            data: null, error: { message: 'DB error' },
                        }),
                    }),
                }),
            }),
        });
        await loadBlockedWords();

        expect(isProfane('fallbackword')).toBe(true);
    });

    it('does not throw when both DB and cache are unavailable', async () => {
        mockedStorage.getItem.mockResolvedValue(null);
        mockFrom.mockReturnValue({
            select: jest.fn().mockReturnValue({
                order: jest.fn().mockReturnValue({
                    limit: jest.fn().mockReturnValue({
                        single: jest.fn().mockResolvedValue({
                            data: null, error: { message: 'DB error' },
                        }),
                    }),
                }),
            }),
        });
        await expect(loadBlockedWords()).resolves.toBeUndefined();
    });
});

import { supabase } from '@/services/supabase';
import { profaneWords, Profanity, ProfanityOptions } from '@2toad/profanity';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { logger } from './logger';
import { useState } from 'react';

const options = new ProfanityOptions();
options.wholeWord = true;

const profanity = new Profanity(options);

/**
 * Returns true if the text contains profane language.
 * Safe to call with null/undefined.
 */
export function isProfane(text: string | null | undefined): boolean {
    if (!text) return false;
    const lower = text.toLowerCase();
    if (customBlockedWords.some(w => lower.includes(w))) return true;
    return profanity.exists(text);
}
/**
 * Throws a user-friendly error if the text contains profane language.
 * Use this at form submission boundaries.
 */
export function assertClean(text: string | null | undefined): void {
    if (isProfane(text)) {
        throw new Error(
            'Your text contains inappropriate language. Please revise before submitting.'
        );
    }
}

const BLOCKED_WORDS_LIST_KEY = '@safepath_cache:blocked_words:list';
const BLOCKED_WORDS_MODIFIED_KEY = '@safepath_cache:blocked_words:last_modified';

let customBlockedWords: string[] = [];

export async function loadBlockedWords(): Promise<void> {
    try {
        const [storedModified, storedList] = await Promise.all([
            AsyncStorage.getItem(BLOCKED_WORDS_MODIFIED_KEY),
            AsyncStorage.getItem(BLOCKED_WORDS_LIST_KEY),
        ]);

        // Check DB for latest modified timestamp
        const { data, error } = await supabase
            .from('blocked_words')
            .select('created_at')
            .order('created_at', { ascending: false })
            .limit(1)
            .single();

        if (error) {
            // DB unavailable — fall back to cache
            if (storedList) {
                customBlockedWords = JSON.parse(storedList);
            }
            return;
        }

        const dbModified: string | null = data?.created_at ?? null;
        if (dbModified && dbModified === storedModified && storedList) {
            // Cache is fresh
            customBlockedWords = JSON.parse(storedList);
            return;
        }

        // Fetch full list
        const { data: rows, error: fetchError } = await supabase
            .from('blocked_words')
            .select('word')
            .order('created_at', { ascending: false });

        if (fetchError) {
            if (storedList) customBlockedWords = JSON.parse(storedList);
            return;
        }

        const words = (rows ?? []).map((r: { word: string }) => r.word);
        customBlockedWords = words;

        await AsyncStorage.setItem(BLOCKED_WORDS_LIST_KEY, JSON.stringify(words));
        if (dbModified) {
            await AsyncStorage.setItem(BLOCKED_WORDS_MODIFIED_KEY, dbModified);
        }
    } catch (error) {
        logger.error('loadBlockedWords failed:', error);
    }
}

export function resetBlockedWordsCache(): void {
    customBlockedWords = [];
}

// TODO: post-launch — extend to support multiple languages for international users
// profaneWords.get('es'), profaneWords.get('fr'), etc.

export function getBuiltInWords(): string[] {
    return profaneWords.get('en') ?? [];
}
